sys = zpk([], [-2 (-1 + 0.6i) (-1 - 0.6i)], 2) %[output:2a09ce71]
T = 0.01;
t = 0:T:30;
u = ones([1 length(t)]);

sysd = c2d(sys, T, 'tustin');
[b, a] = tfdata(sysd, 'v') %[output:0d57132d] %[output:47a1f49b]
writematrix([b.' a.'], "data/dsp_plant.csv")

[sys_y, ~] = step(sys, t);
sysd_y = filter(single(b), single(a), u);

c = orderedcolors("gem");
colororder(c(4:5,:))
figure; %[output:8af9513f]
plot(t, sys_y, '--', t, sysd_y, '-') %[output:8af9513f]
xlabel('t (s)'); %[output:8af9513f]
ylabel('u(t)'); %[output:8af9513f]
legend('Continuous System', 'Discrete System'); %[output:8af9513f]
title('System Response Comparison'); %[output:8af9513f]
grid on; %[output:8af9513f]

writematrix([sysd_y.'], "data/iir_test.csv")
%%
data = readmatrix("data/iir_output.csv");
figure; %[output:8d0bf75d]
plot(t, data(:,1), "--", t, data(:,2), "-") %[output:8d0bf75d]
xlabel('t (s)'); %[output:8d0bf75d]
ylabel('u(t)'); %[output:8d0bf75d]
legend('Reference system', 'DSP-lib System'); %[output:8d0bf75d]
title('System Response Comparison'); %[output:8d0bf75d]
grid on; %[output:8d0bf75d]
%%
[C, info] = pidtune(sys, "PID");

Kp = single(C.Kp);
Ti = single(C.Ki);
Td = single(1/C.Kd);
[Kp Ti Td] %[output:4057f42c]

PID = pidstd(Kp, Ti, Td, 10) %[output:9bfddc61]
G = feedback(PID * sys, 1) %[output:44635a32]

Gd = c2d(G, T, 'forward');
[b, a] = tfdata(Gd, 'v') %[output:565c2beb] %[output:0dba2b2d]

sysd_y = filter(b, a, u);
sys_y = step(G, t);

isstable(b, a) %[output:1455ff70]
isstable(single(b), single(a)) %[output:6b54e850]

figure; %[output:2b062915]
plot(t, sys_y, '--', t, sysd_y, '-') %[output:2b062915]
xlabel('t (s)'); %[output:2b062915]
ylabel('u(t)'); %[output:2b062915]
legend('Continuous System', 'Discrete System'); %[output:2b062915]
title('System Response Comparison'); %[output:2b062915]
grid on; %[output:2b062915]
writematrix(sysd_y.', "data/pid_test.csv")
%%
data = readmatrix("data/pid_output.csv");
figure; %[output:3bf2357d]
plot(t, data(:,1), "--", t, data(:,2), "-") %[output:3bf2357d]
xlabel('t (s)'); %[output:3bf2357d]
ylabel('u(t)'); %[output:3bf2357d]
legend('Reference System', 'DSP-lib System'); %[output:3bf2357d]
title('System Response Comparison'); %[output:3bf2357d]
grid on; %[output:3bf2357d]

